solution.code:
def aliquot_sum(n):
    if not isinstance(n, int) or n <= 0:
        return 0
    return sum(i for i in range(1, n // 2 + 1) if n % i == 0)

if __name__ == "__main__":
    print(f"Aliquot sum of 6: {aliquot_sum(6)}")
